    private string searchTerm = string.Empty;
    private string selectedStatus = string.Empty;
    private List<IBIZWebApp.Models.SalesOrder> orders = new();
    private string errorMessage = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        // Ensure company is loaded from storage before using SelectedCompany
        await CompanyService.LoadSelectedCompanyAsync();
        await LoadOrdersAsync();
    }

    private async Task OnSearchAsync()
    {
        await LoadOrdersAsync();
    }

    private async Task LoadOrdersAsync()
    {
        errorMessage = string.Empty;
        orders = new List<IBIZWebApp.Models.SalesOrder>();
        if (CompanyService.SelectedCompany == null)
        {
            errorMessage = "No company selected. Please log in again.";
            return;
        }

        string url;
        int page = 1;
        int pageSize = 10;
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/search?page={page}&pageSize={pageSize}";
        }
        else
        {
            url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/search?search={Uri.EscapeDataString(searchTerm)}&page={page}&pageSize={pageSize}";
        }
        var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
        var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("CdyKey", cdkey);
        request.Headers.Add("CompanyCode", companyCode);
        var response = await Http.SendAsync(request);
        if (response.IsSuccessStatusCode)
        {
            var json = await response.Content.ReadAsStringAsync();
            var pagedResult = System.Text.Json.JsonSerializer.Deserialize<IBIZWebApp.Models.PagedResponse<IBIZWebApp.Models.SalesOrder>>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
            var filtered = pagedResult?.Items ?? new List<IBIZWebApp.Models.SalesOrder>();
            if (!string.IsNullOrEmpty(selectedStatus))
            {
                filtered = filtered.Where(o => o.Status == selectedStatus).ToList();
            }
            orders = filtered;
        }
        else
        {
            errorMessage = "Failed to load sales orders.";
        }
    }

    private void EditOrder(string? orderId)
    {
        // If orderId is null, empty, or "0", treat as new order
        if (string.IsNullOrEmpty(orderId) || orderId == "0")
        {
            Navigation.NavigateTo("/sales-order-entry");
        }
        else
        {
            Navigation.NavigateTo($"/sales-order-entry/{orderId}");
        }
    }

    private void ViewOrder(string? orderId)
    {
        if (!string.IsNullOrEmpty(orderId))
        {
            Navigation.NavigateTo($"/sales-order-entry/{orderId}?view=true");
        }
    }


    private bool showDeleteConfirm = false;
    private string? orderIdToDelete = null;

    private void ConfirmDelete(string? orderId)
    {
        orderIdToDelete = orderId;
        showDeleteConfirm = true;
    }

    private void CancelDelete()
    {
        showDeleteConfirm = false;
        orderIdToDelete = null;
    }

    private async void DeleteOrderConfirmed()
    {
        if (string.IsNullOrEmpty(orderIdToDelete))
        {
            showDeleteConfirm = false;
            return;
        }
        try
        {
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/{orderIdToDelete}";
            var request = new HttpRequestMessage(HttpMethod.Delete, url);
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                errorMessage = "Order deleted successfully.";
                await LoadOrdersAsync();
            }
            else
            {
                errorMessage = "Failed to delete order.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error deleting order: {ex.Message}";
        }
        showDeleteConfirm = false;
        orderIdToDelete = null;
        StateHasChanged();
    }

    private void CreateNewOrder()
    {
        Navigation.NavigateTo("/sales-order-entry");
    }

